        $self->_create_new_session();
    }
}

sub _validate_session_id {
    my ($self, $session_id) = @_;
    # Only allow hex characters (sha256 output) to prevent path traversal
    return ($session_id =~ /^[a-f0-9]{64}$/) ? 1 : 0;
}

sub _generate_session_id {
    my ($self) = @_;
    my $random_data = join('',
        time(),
        $$,
        rand(999999999),
        $ENV{REMOTE_ADDR}  || '127.0.0.1',
        $ENV{HTTP_USER_AGENT} || 'unknown',
    );
    return Digest::SHA::sha256_hex($random_data);
}

sub _session_file {
    my ($self, $session_id) = @_;
    $session_id ||= $self->{session_id};
    return File::Spec->catfile(
        $self->{session_dir},
        $self->{session_prefix} . $session_id
