sub destroy {
    my ($self) = @_;
    my $file = $self->_session_file();
    if (-e $file) {
        unlink $file or warn "Could not remove session file $file: $!\n";
    }
    $self->{data} = {};
    $self->{session_id} = undef;
}

sub cookie {
    my ($self, %opts) = @_;
    my $cookie = CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id},
        -expires  => '+' . $self->{session_timeout} . 's',
        -path     => $opts{path}     || '/',
        -secure   => $opts{secure}   || 0,
        -httponly  => defined $opts{httponly} ? $opts{httponly} : 1,
        -samesite => $opts{samesite} || 'Strict',
    );
    return $cookie;
}

sub expire_cookie {
    my ($self) = @_;
    my $cookie = CGI::Cookie->new(
        -name    => $self->{cookie_name},
        -value   => '',
        -expires => '-1d',
        -path    => '/',
    );
    return $cookie;
}

sub cleanup_expired {
    my ($self) = @_;
    my $dir    = $self->{session_dir};
    my $prefix = $self->{session_prefix};
    my $count  = 0;

    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory $dir: $!\n";
        return 0;
    };

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /^\Q$prefix\E[a-f0-9]{64}$/;
        my $filepath = File::Spec->catfile($dir, $entry);

        eval {
            my $data = lock_retrieve($filepath);
            if ($data && $data->{_last_access}) {
                if ((time() - $data->{_last_access}) > $self->{session_timeout}) {
                    unlink $filepath;
                    $count++;
                }
            }
        };
        if ($@) {
            # Corrupted file, remove it
            unlink $filepath;
            $count++;
        }
    }
    closedir($dh);
    return $count;
}

